using System.Collections;

class EnvVarCheck
{
    void CheckFlag()
    {
        // On Linux, set via: export MY_FLAG=""
        // .NET 9 breaking change: GetEnvironmentVariable returns null for empty
        // vars on Unix. Use GetEnvironmentVariables() to distinguish "not set"
        // from "explicitly empty".
        var val = Environment.GetEnvironmentVariable("MY_FLAG");
        IDictionary allVars = Environment.GetEnvironmentVariables();
        if (!allVars.Contains("MY_FLAG"))
        {
            Console.WriteLine("MY_FLAG not set, using default");
        }
    }
}

